import React, { createContext, useState, useContext, useEffect, useCallback } from 'react';
import axios from 'axios';
import { useAuth } from './AuthContext';

const CartContext = createContext();

export const useCart = () => useContext(CartContext);

export const CartProvider = ({ children }) => {
  const [cartItems, setCartItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const { token, logout } = useAuth(); // Added logout to handle expired tokens

  const API_URL = 'http://localhost:5000/api';

  const fetchCart = useCallback(async () => {
    if (!token) {
      setCartItems([]);
      return;
    }

    try {
      setLoading(true);
      const response = await axios.get(`${API_URL}/cart`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCartItems(response.data);
    } catch (error) {
      console.error('Error fetching cart:', error);
      if (error.response && error.response.status === 401) {
        // If token is invalid/expired, log the user out
        logout();
      }
    } finally {
      setLoading(false);
    }
  }, [token, API_URL, logout]);

  useEffect(() => {
    fetchCart();
  }, [fetchCart]);

  const addToCart = useCallback(async (productId, quantity = 1) => {
    if (!token) {
      alert("Please login to add items to your cart.");
      return;
    }

    try {
      await axios.post(`${API_URL}/cart/add`, 
        { product_id: productId, quantity },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      await fetchCart();
    } catch (error) {
      console.error('Error adding to cart:', error);
      if (error.response && error.response.status === 401) {
        alert("Your session has expired. Please login again.");
        logout();
      }
    }
  }, [token, API_URL, fetchCart, logout]);

  const updateCartItem = useCallback(async (itemId, quantity) => {
    if (!token) return;
    try {
      await axios.put(`${API_URL}/cart/update/${itemId}`,
        { quantity },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      await fetchCart();
    } catch (error) {
      console.error('Error updating cart:', error);
    }
  }, [token, API_URL, fetchCart]);

  const removeFromCart = useCallback(async (itemId) => {
    if (!token) return;
    try {
      await axios.delete(`${API_URL}/cart/remove/${itemId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      await fetchCart();
    } catch (error) {
      console.error('Error removing from cart:', error);
    }
  }, [token, API_URL, fetchCart]);

  const getCartTotal = useCallback(() => {
    return cartItems.reduce((total, item) => total + (item.price * item.quantity), 0);
  }, [cartItems]);

  return (
    <CartContext.Provider value={{
      cartItems,
      loading,
      addToCart,
      updateCartItem,
      removeFromCart,
      getCartTotal,
      fetchCart
    }}>
      {children}
    </CartContext.Provider>
  );
};
